void topView(Node* root) {
    if (!root)
        return;

    int map[2000] = {0}; // Initialize map with 0s
    char visited[2000] = {0}; // Array to track visited horizontal distances

    Node* queue[10000];
    int horizontalDistance[10000];
    int front = 0, rear = 0;

    queue[rear] = root;
    horizontalDistance[rear++] = 1000; // Centered at 1000

    int minIndex = 1000, maxIndex = 1000;

    while (front < rear) {
        Node* node = queue[front];
        int hd = horizontalDistance[front++];

        if (!visited[hd]) { // Only set the value if it hasn't been visited
            visited[hd] = 1;
            map[hd] = node->val;
            if (hd < minIndex) minIndex = hd;
            if (hd > maxIndex) maxIndex = hd;
        }

        if (node->left) {
            queue[rear] = node->left;
            horizontalDistance[rear++] = hd - 1;
        }
        if (node->right) {
            queue[rear] = node->right;
            horizontalDistance[rear++] = hd + 1;
        }
    }

    for (int i = minIndex; i <= maxIndex; i++) {
        if (visited[i]) {
            printf("%d ", map[i]);
        }
    }
    printf("\n");
}

